class PostVoting{constructor(){this.upvoteButton=document.getElementById("upvote-button"),this.downvoteButton=document.getElementById("downvote-button"),this.scoreCount=document.getElementById("post-score-count"),this.postID=document.getElementById("content-container").dataset.postId,this.upvoteButton.onclick=()=>{this.addUpvote()},this.downvoteButton.onclick=()=>{this.addDownvote()}}sendVote(t){let o={url:"/api/v1/posts/vote",method:"POST",data:JSON.stringify({post_id:this.postID,type:t}),headers:{"Content-Type":"application/json"}};$.ajax(o).done(t=>{this.updateButtons(t)})}addUpvote(){this.upvoteButton.classList.contains("disabled")||(this.upvoteButton.classList.add("disabled"),this.downvoteButton.classList.add("disabled"),this.sendVote("upvote"))}addDownvote(){this.downvoteButton.classList.contains("disabled")||(this.upvoteButton.classList.add("disabled"),this.downvoteButton.classList.add("disabled"),this.sendVote("downvote"))}updateButtons(t){this.scoreCount.innerText=t.score,t.score>0?this.scoreCount.className="positive":t.score<0?this.scoreCount.className="negative":this.scoreCount.className="neutral",t.has_downvoted?(this.downvoteButton.classList.add("voted"),this.upvoteButton.classList.remove("voted")):t.has_upvoted?(this.upvoteButton.classList.add("voted"),this.downvoteButton.classList.remove("voted")):t.has_downvoted||t.has_upvoted||(this.upvoteButton.classList.remove("voted"),this.downvoteButton.classList.remove("voted")),this.upvoteButton.classList.remove("disabled"),this.downvoteButton.classList.remove("disabled")}}export{PostVoting};